export const generateOfflineMoneyCounting = async (options: GeneratorOptions): Promise<MoneyCountingData[]> => {
    const { worksheetCount, difficulty, moneyVariant, moneyCurrencyType, maxAmount = 100 } = options;

    return Array.from({ length: worksheetCount }, () => {
        const puzzles = [];
        const count = difficulty === 'Başlangıç' ? 3 : (difficulty === 'Orta' ? 4 : 5);

        for (let i = 0; i < count; i++) {
            const notePool = [5, 10, 20, 50, 100].filter(v => v <= maxAmount);
            const coinPool = [0.1, 0.25, 0.5, 1];

            let selectedNotes: any[] = [];
            let selectedCoins: any[] = [];

            if (moneyCurrencyType !== 'coins-only') {
                const noteVal = notePool[getRandomInt(0, notePool.length - 1)];
                selectedNotes.push({ value: noteVal, count: getRandomInt(1, 2) });
            }
            if (moneyCurrencyType !== 'notes-only') {
                const coinVal = coinPool[getRandomInt(0, coinPool.length - 1)];
                selectedCoins.push({ value: coinVal, count: getRandomInt(1, 5) });
            }

            const total = selectedNotes.reduce((acc, n) => acc + (n.value * n.count), 0) + 
                          selectedCoins.reduce((acc, c) => acc + (c.value * c.count), 0);

            const distractors = new Set<string>();
            while(distractors.size < 3) {
                const d = (total + (Math.random() > 0.5 ? 1 : -1) * getRandomInt(1, 5)).toFixed(2);
                if (parseFloat(d) > 0 && parseFloat(d) !== total) distractors.add(d + " TL");
            }

            puzzles.push({
                id: `money-${i}-${Date.now()}`,
                type: 'count' as const,
                notes: selectedNotes,
                coins: selectedCoins,
                question: "Toplam miktar ne kadardır?",
                options: shuffle([total.toFixed(2) + " TL", ...Array.from(distractors)]),
                answer: total.toFixed(2) + " TL"
            });
        }

        return {
            title: "Paralarımız",
            instruction: "Görseldeki paraları sayıp toplam değeri işaretleyin.",
            pedagogicalNote: "Finansal okuryazarlık ve sayısal toplama becerisini destekler.",
            variant: moneyVariant as any || 'basic-counting',
            currencyType: moneyCurrencyType as any || 'mixed',
            puzzles
        };
    });
};

