// --- ENHANCED MONEY ICON COMPONENT ---
const MoneyIcon: React.FC<{ value: number, type: 'coin' | 'note' }> = ({ value, type }) => {
    if (type === 'coin') {
        const sizeClass = value >= 1 ? 'w-14 h-14' : (value >= 0.5 ? 'w-12 h-12' : 'w-10 h-10');
        const colorClass = value >= 1 ? 'bg-gradient-to-br from-amber-200 to-amber-500 border-amber-600' : 'bg-gradient-to-br from-zinc-200 to-zinc-400 border-zinc-500';
        return (
            <div className={`${sizeClass} rounded-full border-4 ${colorClass} flex flex-col items-center justify-center font-black text-zinc-800 shadow-lg transform hover:scale-110 transition-transform relative`}>
                <span className="text-xs leading-none">{value < 1 ? value * 100 : value}</span>
                <span className="text-[7px] uppercase tracking-tighter">{value < 1 ? 'KR' : 'TL'}</span>
                <div className="absolute inset-1 border border-white/30 rounded-full pointer-events-none"></div>
            </div>
        );
    }

    // Notes colors by TL standard
    const noteColors: Record<number, string> = {
        5: 'bg-orange-100 border-orange-400 text-orange-900',
        10: 'bg-red-100 border-red-400 text-red-900',
        20: 'bg-emerald-100 border-emerald-400 text-emerald-900',
        50: 'bg-amber-100 border-amber-400 text-amber-900',
        100: 'bg-blue-100 border-blue-400 text-blue-900',
        200: 'bg-purple-100 border-purple-400 text-purple-900'
    };

    const colorStyle = noteColors[value] || 'bg-zinc-100 border-zinc-400';

    return (
        <div className={`w-28 h-14 ${colorStyle} border-2 flex flex-col items-center justify-center font-black rounded-lg relative overflow-hidden shadow-md group transform hover:rotate-2 transition-all`}>
            <div className="absolute top-1 left-1 text-[8px] opacity-40">TÜRKİYE CUMHURİYETİ</div>
            <div className="text-lg">{value}</div>
            <div className="text-[8px] tracking-widest">TÜRK LİRASI</div>
            <div className="absolute -right-4 -bottom-4 w-12 h-12 bg-white/10 rounded-full"></div>
            {/* Hologram strip */}
            <div className="absolute left-4 top-0 bottom-0 w-2 bg-gradient-to-b from-white/0 via-white/40 to-white/0 opacity-50"></div>
        </div>
    );
};

