/* Local UI Helpers for Generator Controls */
const CompactSelect = ({ label, value, onChange, options, icon }: any) => (
    <div className="flex flex-col gap-1.5">
        <label className="text-[10px] font-black text-zinc-400 uppercase tracking-widest flex items-center gap-1.5">
            <i className={`fa-solid ${icon}`}></i> {label}
        </label>
        <select 
            value={value} 
            onChange={(e) => onChange(e.target.value)}
            className="w-full p-2.5 bg-white dark:bg-zinc-900 border border-zinc-200 dark:border-zinc-700 rounded-xl text-sm font-bold outline-none focus:ring-2 focus:ring-indigo-500/20 transition-all"
        >
            {options.map((opt: any) => <option key={opt.value} value={opt.value}>{opt.label}</option>)}
        </select>
    </div>
);

const CompactToggleGroup = ({ label, selected, onChange, options }: any) => (
    <div className="flex flex-col gap-2">
        <label className="text-[10px] font-black text-zinc-400 uppercase tracking-widest">{label}</label>
        <div className="flex bg-zinc-100 dark:bg-zinc-900 rounded-xl p-1 gap-1 border border-zinc-200 dark:border-zinc-700">
            {options.map((opt: any) => (
                <button
                    key={opt.value}
                    onClick={() => onChange(opt.value)}
                    className={`flex-1 py-2 rounded-lg text-[10px] font-black transition-all ${selected === opt.value ? 'bg-white dark:bg-zinc-600 shadow-sm text-indigo-600 dark:text-indigo-300' : 'text-zinc-500 hover:text-zinc-700'}`}
                >
                    {opt.label}
                </button>
            ))}
        </div>
    </div>
);

const CompactSlider = ({ label, value, onChange, min, max, step, unit, icon }: any) => (
    <div className="flex flex-col gap-1.5">
        <div className="flex justify-between items-center">
            <label className="text-[10px] font-black text-zinc-400 uppercase tracking-widest flex items-center gap-1.5">
                <i className={`fa-solid ${icon}`}></i> {label}
            </label>
            <span className="text-[10px] font-mono font-black text-indigo-600">{value}{unit}</span>
        </div>
        <input 
            type="range" min={min} max={max} step={step} value={value} 
