import { Type } from "@google/genai";
import { generateWithSchema } from '../geminiClient';
import { GeneratorOptions, 
    NumberSenseData, VisualArithmeticData, SpatialGridData, ConceptMatchData, EstimationData,
    RealLifeProblemData, ActivityType, MathMemoryCardsData, MoneyCountingData
} from '../../types';
import { getMathPrompt } from './prompts';

const PEDAGOGICAL_PROMPT = `
[ROL: KIDEMLİ ÖZEL EĞİTİM UZMANI]
Diskalkuli destekli materyal üret. Sadece JSON döndür.
`;

export const generateNumberSenseFromAI = async (options: GeneratorOptions): Promise<NumberSenseData[]> => {
    const { difficulty, worksheetCount } = options;
    const prompt = `Sayı Hissi etkinliği üret. Seviye: ${difficulty}. ${PEDAGOGICAL_PROMPT}`;
    const schema = {
        type: Type.ARRAY,
        items: {
            type: Type.OBJECT,
            properties: {
                title: { type: Type.STRING },
                instruction: { type: Type.STRING },
                pedagogicalNote: { type: Type.STRING },
                layout: { type: Type.STRING },
                exercises: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            type: { type: Type.STRING },
                            values: { type: Type.ARRAY, items: { type: Type.NUMBER } },
                            target: { type: Type.NUMBER },
                            visualType: { type: Type.STRING }
                        },
                        required: ['type', 'values']
                    }
                }
            },
            required: ['title', 'instruction', 'exercises']
        }
    };
    return generateWithSchema(prompt, schema);
};

export const generateMoneyCountingFromAI = async (options: GeneratorOptions): Promise<MoneyCountingData[]> => {
    const { difficulty, moneyVariant, moneyCurrencyType, maxAmount, includeScenarios, studentContext, worksheetCount } = options;

    const variantRules = {
        'basic-counting': 'Verilen para görsellerinin toplam değerini buldur.',
        'comparison': 'İki farklı para grubunu yan yana göster ve hangisinin daha büyük olduğunu veya aradaki farkı buldur.',
        'shopping-ai': 'Öğrencinin ilgi alanlarına uygun bir ürün ve fiyat belirle (Örn: ' + (studentContext?.interests?.join(', ') || 'oyuncaklar') + '), elindeki para ile alıp alamayacağını sorgula.',
        'change-calc': 'Bir ürün fiyatı ve ödenen miktarı ver, para üstünü hesaplat.'
    }[moneyVariant as string] || 'Para sayma';

    const rule = `
    [GÖREV]: Diskalkuli Dostu Para ve Finansal Okuryazarlık Etkinliği Üret.
    VARYANT: ${variantRules}
    PARA TİPİ: ${moneyCurrencyType}
    LİMİT: Maksimum ${maxAmount} TL civarı işlemler.
    ${includeScenarios ? 'Kişiselleştirilmiş, ilgi çekici kısa senaryolar kurgula (Örn: "Uzay marketinden yakıt alma").' : ''}

    TEKNİK KISITLAMALAR:
    1. Sadece geçerli Türk Lirası birimlerini kullan (1, 5, 10, 20, 50, 100, 200 TL). Madeni paralarda 0.10, 0.25, 0.50 ve 1 TL kullan.
    2. 'puzzles' dizisindeki her öğe için 'notes' ve 'coins' objelerini doldur.
    3. Seçenekler (options) birbirine yakın ama net çeldiriciler içermeli.
    4. GÖRSEL: Her puzzle için o paraları veya alınan ürünü betimleyen 'imagePrompt' ekle.
    `;

    const prompt = getMathPrompt("Gelişmiş Paralarımız Atölyesi", difficulty, rule, studentContext);

    const schema = {
        type: Type.ARRAY,
        items: {
            type: Type.OBJECT,
            properties: {
                title: { type: Type.STRING },
                instruction: { type: Type.STRING },
                pedagogicalNote: { type: Type.STRING },
                variant: { type: Type.STRING },
                puzzles: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            id: { type: Type.STRING },
                            type: { type: Type.STRING },
                            scenarioText: { type: Type.STRING, nullable: true },
                            question: { type: Type.STRING },
                            notes: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { value: { type: Type.NUMBER }, count: { type: Type.NUMBER } } } },
                            coins: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { value: { type: Type.NUMBER }, count: { type: Type.NUMBER } } } },
                            itemPrice: { type: Type.NUMBER, nullable: true },
                            paidAmount: { type: Type.NUMBER, nullable: true },
                            options: { type: Type.ARRAY, items: { type: Type.STRING } },
                            answer: { type: Type.STRING },
                            imagePrompt: { type: Type.STRING }
                        },
                        required: ['question', 'options', 'answer']
                    }
                }
            },
            required: ['title', 'instruction', 'puzzles']
        }
    };

    return await generateWithSchema(prompt, schema, 'gemini-3-flash-preview');
};

export const generateMathMemoryCardsFromAI = async (options: GeneratorOptions): Promise<MathMemoryCardsData[]> => {
    const { difficulty, itemCount, variant, selectedOperations, studentContext } = options;

    const rule = `
    [GÖREV: MATEMATİK HAFIZA KARTLARI ÜRET]
    ZORLUK: ${difficulty}
    TOPLAM KART SAYISI: ${itemCount || 16}
    EŞLEŞTİRME MODU: ${variant} (op-res: İşlem-Sonuç, vis-num: Görsel-Rakam, eq-eq: Denk İşlemler)
    KULLANILACAK İŞLEMLER: ${selectedOperations?.join(', ') || 'Toplama, Çıkarma'}

    TASARIM KURALLARI:
    1. Bir sayfada tam olarak ${itemCount || 16} kart olsun. 
    2. 'cards' dizisinde her öğe bir karttır. 'pairId' alanı aynı olan iki kart birbirinin eşidir.
    3. 'vis-num' modunda kartlardan biri mutlaka 'visual' tipinde olmalı ve 'visualType' belirtilmelidir (ten-frame, blocks, dice).
    4. Sayılar ve işlemler zorluk seviyesine uygun olmalıdır.

    ÇIKTI: JSON formatında, A4 sayfasını dolduracak şekilde 'cards' dizisi döndür.
    `;

    const prompt = getMathPrompt("Matematik Hafıza Atölyesi", difficulty, rule, studentContext);

    const schema = {
        type: Type.ARRAY,
        items: {
            type: Type.OBJECT,
            properties: {
                title: { type: Type.STRING },
                instruction: { type: Type.STRING },
                pedagogicalNote: { type: Type.STRING },
                cards: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
