                        />
                    </div>
                </div>
            );
        }

        // --- SYLLABLE MASTER LAB ---
        if (activity.id === ActivityType.SYLLABLE_MASTER_LAB) {
            return (
                <div className="space-y-5 animate-in fade-in duration-300">
                    <CompactSelect 
                        label="Çalışma Modu" 
                        value={options.variant || 'split'} 
                        onChange={(v:any) => handleChange('variant', v)}
