        }

        // --- SYNONYM ANTONYM MATCH ---
        if (activity.id === ActivityType.SYNONYM_ANTONYM_MATCH) {
            return (
                <div className="space-y-5 animate-in fade-in duration-300">
                    <CompactSelect 
                        label="Çalışma Odağı" 
