    const [options, setOptions] = useState<GeneratorOptions>({
        mode: 'fast',
        difficulty: 'Orta',
        worksheetCount: 1,
        itemCount: activity.id === ActivityType.SYLLABLE_MASTER_LAB ? 24 : 16,
        gridSize: 4,
        topic: '',
        distractionLevel: 'medium',
        visualType: 'geometric',
        logicModel: 'identity',
        numberRange: '1-50',
        findDiffType: 'linguistic',
        showSumTarget: true,
        mapInstructionTypes: ['spatial_logic', 'linguistic_geo', 'attribute_search'],
        emphasizedRegion: 'all',
        showCityNames: true,
        markerStyle: 'circle',
        customInput: '',
        variant: 'analog-to-digital',
        case: 'upper',
        fontFamily: 'OpenDyslexic',
        syllableRange: '2-3',
        selectedOperations: ['add', 'sub'],
        visualStyle: 'mixed',
        is24Hour: false,
        showNumbers: true,
        showTicks: true,
        showOptions: true,
        showHands: true,
        // Para Etkinliği Varsayılanları
        moneyVariant: 'basic-counting',
        moneyCurrencyType: 'mixed',
        includeScenarios: true,
        maxAmount: 100
    });

    const handleChange = (key: keyof GeneratorOptions, value: any) => {
        setOptions(prev => ({ ...prev, [key]: value }));
    };

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            const reader = new FileReader();
            reader.onload = (ev) => {
                const base64 = ev.target?.result as string;
                setUploadedImage(base64);
                handleChange('customInput', base64);
            };
            reader.readAsDataURL(file);
        }
    };

    const handleStudentChange = (id: string) => {
        if (id === 'anonymous') {
            setActiveStudent(null);
        } else {
            const student = students.find(s => s.id === id);
            if (student) setActiveStudent(student);
        }
    };

    const renderActivityControls = () => {
        // --- PARALARIMIZ (DERİNLEMESİNE GELİŞTİRİLDİ) ---
