import { Type } from "@google/genai";
import { generateWithSchema } from '../geminiClient';
import { GeneratorOptions, MathPuzzleData, ShapeCountingData } from '../../types';

const PEDAGOGICAL_PROMPT = `
ÜST DÜZEY EĞİTİM İÇERİĞİ OLUŞTURMA YÖNERGESİ (PREMIUM KALİTE):
1.  **Rol:** Sen, "Özel Eğitim ve Üstün Yetenekliler" için materyal hazırlayan uzman bir pedagogsun.
2.  **CRA Modeli:** Somut (nesneler) -> Temsili (denklemler) -> Soyut (sayılar) akışını izle.
3.  **Çıktı:** Sadece geçerli JSON. Markdown veya açıklama yapma.
4.  **Zorluk Dengesi:** Sayılar kesinlikle tam sayı olmalı. Bölme işlemlerinde kalan olmamalı.
`;

export const generateMathPuzzleFromAI = async (options: GeneratorOptions): Promise<MathPuzzleData[]> => {
  const { topic, itemCount, difficulty, variableCount, puzzleStyle, numberRange, studentContext } = options;

  const studentInfo = studentContext ? `Öğrenci: ${studentContext.name}, İlgi Alanları: ${studentContext.interests.join(',')}` : "";

  const prompt = `
    [GÖREV]: "${difficulty}" seviyesinde, '${topic || 'Genel'}' temalı ${itemCount} adet "Matematiksel Gizem" bulmacası üret.
    ${studentInfo}

    KURALLAR:
    1. Stil: ${puzzleStyle === 'proportional' ? 'Orantısal (Yarım nesneler, farklı renkli detaylar değer değiştirir)' : 'Sistemik Denklem (X+Y=10 tarzı)'}.
    2. Değişken Sayısı: ${variableCount} adet farklı nesne kullan.
    3. Sayı Aralığı: ${numberRange} içinde çalış.
    4. Akış: 
       - Satır 1: Aynı nesnelerin toplamı (X+X=?). 
       - Satır 2: X + Yeni Nesne (Y) = ?. 
       - Satır 3: Y + Z = ? (Eğer 3 değişken varsa).
       - Final: Karmaşık bir işlem (Örn: X * Y - Z = ?).
    5. 'isHalf' alanı: Eğer bir nesnenin yarısı kullanılıyorsa true yap.
    6. Görsel Tasviri: Her nesne için 'imagePrompt' alanını İngilizce ve detaylı doldur. Stil: "Minimalist icon, flat vector, white background".

    ${PEDAGOGICAL_PROMPT}
  `;

  const singleSchema = {
    type: Type.OBJECT,
    properties: {
      title: { type: Type.STRING },
      instruction: { type: Type.STRING },
      pedagogicalNote: { type: Type.STRING },
      puzzles: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            id: { type: Type.STRING },
            complexity: { type: Type.STRING },
            variableCount: { type: Type.NUMBER },
            equations: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  leftSide: { 
                    type: Type.ARRAY, 
                    items: { 
                      type: Type.OBJECT, 
                      properties: { 
                        objectName: { type: Type.STRING }, 
                        multiplier: { type: Type.NUMBER },
                        isHalf: { type: Type.BOOLEAN }
                      } 
                    } 
                  },
                  operator: { type: Type.STRING },
                  rightSide: { type: Type.NUMBER }
                },
                required: ['leftSide', 'operator', 'rightSide']
              }
            },
            finalQuestion: { type: Type.STRING },
            answer: { type: Type.STRING },
            objects: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  name: { type: Type.STRING },
                  value: { type: Type.NUMBER },
                  imagePrompt: { type: Type.STRING }
                },
                required: ['name', 'value', 'imagePrompt']
              }
            }
          },
          required: ['equations', 'finalQuestion', 'answer', 'objects']
        }
      }
    },
    required: ['title', 'puzzles', 'instruction']
  };

  return await generateWithSchema(prompt, { type: Type.ARRAY, items: singleSchema }, 'gemini-3-flash-preview');
};

export const generateShapeCountingFromAI = async (options: GeneratorOptions): Promise<ShapeCountingData[]> => {
    // ... (unchanged)
    const { difficulty, worksheetCount } = options;
    const prompt = `"${difficulty}" seviyesinde "Şekil Sayma". Karmaşık, iç içe geçmiş şekiller üret. ${PEDAGOGICAL_PROMPT}`;
    const singleSchema = { type: Type.OBJECT, properties: { title: { type: Type.STRING }, instruction: { type: Type.STRING }, pedagogicalNote: { type: Type.STRING }, figures: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { svgPaths: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { d: { type: Type.STRING }, fill: { type: Type.STRING } }, required: ["d", "fill"] } }, targetShape: { type: Type.STRING }, correctCount: { type: Type.INTEGER } }, required: ["svgPaths", "targetShape", "correctCount"] } } }, required: ["title", "instruction", "figures"] };
    return generateWithSchema(prompt, { type: Type.ARRAY, items: singleSchema });
};

