    return (
        <div 
            className="transition-all duration-300 flex items-center justify-center"
            style={{ 
                transform: `rotate(${item.rotation || 0}deg) scale(${item.scale || 1}) ${item.isMirrored ? 'scaleX(-1)' : ''}`,
