import React from 'react';
import { BaklavaReadingData } from '../../types';
import { PedagogicalHeader } from './common';
import { EditableElement, EditableText } from '../Editable';

// ... existing imports
export const BaklavaReadingSheet: React.FC<{ data: BaklavaReadingData }> = ({ data }) => {
    return (
        <div className="flex flex-col h-full bg-white p-1 font-lexend relative overflow-hidden">
            <PedagogicalHeader title={data.title} instruction={data.instruction} note={data.pedagogicalNote} data={data} />

            <div className="flex-1 flex flex-col gap-16 py-10 relative">
                {/* Merkez Odak Çizgisi (Fixation Line) */}
                {data.settings.showFocusLine && (
                    <div className="absolute left-1/2 top-0 bottom-0 w-px border-l-2 border-dashed border-zinc-200 -translate-x-1/2 z-0 pointer-events-none"></div>
                )}

                {(data.patterns || []).map((pattern, pIdx) => (
                    <div key={pIdx} className="relative z-10 flex flex-col items-center">
                        {pattern.lines.map((line, lIdx) => {
                            // Baklava şeklini vurgulamak için dikeyde orta satırı bul
                            const mid = Math.floor(pattern.lines.length / 2);
                            const distFromMid = Math.abs(lIdx - mid);
                            const scale = 1 + ( (mid - distFromMid) * 0.05 ); // Merkeze yaklaştıkça hafif büyüme

                            return (
                                <EditableElement 
                                    key={lIdx} 
                                    className="py-1.5 transition-all hover:bg-indigo-50/50 rounded-lg px-4 group/line"
                                    style={{ transform: `scale(${scale})` }}
                                >
                                    <div className="flex items-center justify-center gap-4">
                                        {/* Sol Kanat Boşluğu */}
                                        <div className="flex-1 text-right text-transparent select-none font-mono">
                                            {".".repeat(Math.max(0, 10 - line.length/2))}
                                        </div>

                                        {/* Ana Metin */}
                                        <div className="relative flex items-center justify-center">
                                            {data.settings.showCenterDot && (
                                                <div className="absolute left-1/2 top-1/2 -translate-x-1/2 -translate-y-1/2 w-1.5 h-1.5 bg-rose-500/20 rounded-full group-hover/line:bg-rose-500 transition-colors"></div>
                                            )}
                                            <p className={`
                                                font-bold tracking-[0.1em] text-zinc-800 uppercase text-center whitespace-nowrap
                                                ${distFromMid === 0 ? 'text-indigo-600 text-xl' : 'text-lg opacity-80'}
                                            `}>
                                                <EditableText value={line} tag="span" />
                                            </p>
                                        </div>

                                        {/* Sağ Kanat Boşluğu */}
                                        <div className="flex-1 text-left text-transparent select-none font-mono">
                                            {".".repeat(Math.max(0, 10 - line.length/2))}
                                        </div>
                                    </div>
                                </EditableElement>
                            );
                        })}
                    </div>
                ))}
            </div>

            <div className="mt-auto pt-4 border-t border-zinc-100 flex justify-between items-center px-4 opacity-30">
                <div className="flex flex-col">
                    <span className="text-[8px] font-black text-zinc-400 uppercase tracking-widest">Egzersiz</span>
                    <span className="text-[10px] font-bold text-zinc-800">Periferik Görme Eğitimi</span>
                </div>
                <p className="text-[7px] text-zinc-400 font-bold uppercase tracking-[0.4em]">Bursa Disleksi AI • Optik Akış v1.0</p>
            </div>
        </div>
    );
};

