import { GoogleGenAI, Type } from "@google/genai";
import { generateWithSchema } from '../geminiClient';
import { GeneratorOptions, BaklavaReadingData } from '../../types';
import { PEDAGOGICAL_BASE } from './prompts';

// ... existing code
export const generateBaklavaReadingFromAI = async (options: GeneratorOptions): Promise<BaklavaReadingData[]> => {
    const { difficulty, topic, itemCount = 3, showFocusLine, expansionFactor } = options;

    const prompt = `
    [ROL: HIZLI OKUMA VE DİSLEKSİ EĞİTMENİ]
    GÖREV: "${difficulty}" seviyesinde, "${topic || 'Genel'}" temalı "Baklava Desenli (Piramit) Hızlı Okuma" egzersizleri üret.

    YAPI KURALLARI:
    1. Her pattern (baklava) dikey simetrik olmalı. 
    2. Satır 1: Tek bir kelime.
    3. Satır 2: Önceki kelime + 1 yeni kelime.
    4. Ortaya kadar genişle (Genişlik: ${difficulty === 'Uzman' ? '6-8 kelime' : '4-5 kelime'}).
    5. Ortadan sonra simetrik olarak kelime eksilterek tek kelimeye geri dön.
    6. Kelimeler anlamlı bir cümle bütünü oluşturmalı.

    ADET: ${itemCount} farklı baklava deseni.

    ${PEDAGOGICAL_BASE}
    `;

    const schema = {
        type: Type.ARRAY,
        items: {
            type: Type.OBJECT,
            properties: {
                title: { type: Type.STRING },
                instruction: { type: Type.STRING },
                pedagogicalNote: { type: Type.STRING },
                patterns: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            id: { type: Type.STRING },
                            lines: { type: Type.ARRAY, items: { type: Type.STRING } },
                            accentWord: { type: Type.STRING }
                        },
                        required: ['lines']
                    }
                }
            },
            required: ['title', 'instruction', 'patterns']
        }
    };

    const result = await generateWithSchema(prompt, schema);
    return result.map((page: any) => ({
        ...page,
        settings: {
            showFocusLine: showFocusLine ?? true,
            expansionFactor: expansionFactor ?? 1.5,
            showCenterDot: true,
