import { GeneratorOptions, BaklavaReadingData } from '../../types';

export const generateOfflineBaklavaReading = async (options: GeneratorOptions): Promise<BaklavaReadingData[]> => {
    const { worksheetCount, difficulty } = options;

    const sampleSentences = [
        ["Ali", "Ali bak", "Ali topa bak", "Ali kırmızı topa bak", "Ali topa bak", "Ali bak", "Ali"],
        ["Oku", "Kitap oku", "Her gün kitap oku", "Bilgi için her gün kitap oku", "Her gün kitap oku", "Kitap oku", "Oku"],
        ["Bak", "Gökyüzüne bak", "Mavi gökyüzüne bak", "Güneşli mavi gökyüzüne bak", "Mavi gökyüzüne bak", "Gökyüzüne bak", "Bak"]
    ];

    return Array.from({ length: worksheetCount }, () => ({
        title: "Baklava Desenli Hızlı Okuma",
        instruction: "Gözlerini sayfanın ortasındaki dikey çizgiden ayırmadan, kelimeleri tek bir bakışta okumaya çalış.",
        pedagogicalNote: "Fiksasyon (odaklanma) alanını genişleterek okuma hızını ve anlama kalitesini artırır.",
        patterns: sampleSentences.map((lines, i) => ({
            id: `bak-${i}`,
            lines: lines
        })),
        settings: {
            showFocusLine: true,
            expansionFactor: 1.2,
            showCenterDot: true,
            symmetry: 'full',
            alignment: 'center'
        }
    }));
};

