export const SheetRenderer: React.FC<{ activityType: ActivityType, data: any }> = ({ activityType, data }) => {
    // Math Studio handling
    if (data.isMathStudio) {
        // ... special rendering logic for MathStudio
    }

    switch (activityType) {
        case ActivityType.MATH_PUZZLE: return <Math.MathPuzzleSheet data={data} />;
        case ActivityType.NUMBER_PATTERN: return <Math.NumberPatternSheet data={data} />;
        case ActivityType.STORY_COMPREHENSION: return <Verbal.StoryComprehensionSheet data={data} />;
        case ActivityType.FIND_THE_DIFFERENCE: return <Visual.FindTheDifferenceSheet data={data} />;
        case ActivityType.VISUAL_ODD_ONE_OUT: return <Visual.VisualOddOneOutSheet data={data} />;
        case ActivityType.NUMBER_SEARCH: return <Memory.NumberSearchSheet data={data} />;
        case ActivityType.STROOP_TEST: return <Memory.StroopTestSheet data={data} />;
        case ActivityType.BURDON_TEST: return <Memory.BurdonTestSheet data={data} />;
        case ActivityType.BAKLAVA_READING: return <Dyslexia.BaklavaReadingSheet data={data} />;
        case ActivityType.ATTENTION_FOCUS: return <Memory.AttentionFocusSheet data={data} />;
        case ActivityType.HANDWRITING_PRACTICE: return <Dyslexia.HandwritingPracticeSheet data={data} />;
        case ActivityType.SYLLABLE_WORD_BUILDER: return <New.SyllableWordBuilderSheet data={data} />;
        // ... more cases
        default:
            return <div className="p-8 text-center text-zinc-400 italic">Bu etkinlik türü ({activityType}) henüz desteklenmiyor.</div>;
    }
};

