export const generateKendokuFromAI = async (options: GeneratorOptions): Promise<KendokuData[]> => {
    const { difficulty, worksheetCount, studentContext, selectedOperations } = options;

    const size = difficulty === 'Başlangıç' ? 3 : (difficulty === 'Orta' ? 4 : (difficulty === 'Zor' ? 5 : 6));
    const ops = selectedOperations?.length ? selectedOperations.join(', ') : 'Toplama, Çıkarma, Çarpma, Bölme';

    const rule = `
    [GÖREV: KENDOKU (KENKEN) MANTIKSAL MATEMATİK BULMACASI ÜRET]
    GRID BOYUTU: ${size}x${size}
    ZORLUK: ${difficulty}
    İŞLEMLER: ${ops}

    TASARIM KURALLARI:
    1. ${size}x${size}'lık bir Latin Kare (Latin Square) oluştur (her satır/sütun 1'den ${size}'e kadar rakam içerir).
    2. Tüm hücreleri kapsayan "Kafesler" (Cages) belirle. 
    3. Her kafes için bir hedef (target) ve operatör (operation: +, -, x, /) ata.
    4. Kafes içindeki sayılar operatör ile işleme girdiğinde hedef sayıyı vermelidir.
    5. Tek hücreli kafeslerde operatör olmaz, sadece sayı hedef olarak yazılır.
    6. ÇIKTI: 'grid' alanı başlangıç için boş (null) olmalı, 'solution' tam dolmalı.
    7. 'cages' listesinde her kafesin hücre koordinatlarını {row, col} olarak ver.

    JSON yapısını bozma.
    `;

    const prompt = getMathPrompt("Kendoku Mantık Atölyesi", difficulty, rule, studentContext);

    const schema = {
        type: Type.ARRAY,
        items: {
            type: Type.OBJECT,
            properties: {
                title: { type: Type.STRING },
                instruction: { type: Type.STRING },
                pedagogicalNote: { type: Type.STRING },
                puzzles: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            size: { type: Type.INTEGER },
                            grid: { type: Type.ARRAY, items: { type: Type.ARRAY, items: { type: Type.INTEGER, nullable: true } } },
                            solution: { type: Type.ARRAY, items: { type: Type.ARRAY, items: { type: Type.INTEGER } } },
                            cages: {
                                type: Type.ARRAY,
                                items: {
                                    type: Type.OBJECT,
                                    properties: {
                                        cells: { 
                                            type: Type.ARRAY, 
                                            items: { 
                                                type: Type.OBJECT, 
                                                properties: { row: { type: Type.INTEGER }, col: { type: Type.INTEGER } } 
                                            } 
                                        },
                                        operation: { type: Type.STRING },
                                        target: { type: Type.INTEGER }
                                    },
                                    required: ['cells', 'target']
                                }
                            }
                        },
                        required: ['size', 'grid', 'cages']
                    }
                }
            },
            required: ['title', 'puzzles', 'instruction']
        }
    };

    return await generateWithSchema(prompt, schema, 'gemini-3-flash-preview');
};

