import { GeneratorOptions, NumberPatternData, NumberPyramidData, OddEvenSudokuData, KendokuData, MoneyCountingData, MathMemoryCardsData, ClockReadingData, RealLifeProblemData, MathPuzzleData, NumberLogicRiddleData } from '../../types';
import { shuffle, getRandomInt, getRandomItems, generateLatinSquare } from './helpers';

export const generateOfflineKendoku = async (options: GeneratorOptions): Promise<KendokuData[]> => {
    const { worksheetCount, difficulty } = options;
    const size = difficulty === 'Başlangıç' ? 3 : (difficulty === 'Orta' ? 4 : 5);

    return Array.from({ length: worksheetCount }, () => {
        const solution = generateLatinSquare(size);
        const grid = Array.from({ length: size }, () => Array(size).fill(null));
        const cages: any[] = [];
        const visited = new Set();

        for (let r = 0; r < size; r++) {
            for (let c = 0; c < size; c++) {
                if (visited.has(`${r},${c}`)) continue;

                // Simple cage builder: try to group 1 or 2 neighbors
                const cageCells = [{ row: r, col: c }];
                visited.add(`${r},${c}`);

                if (Math.random() > 0.4 && c + 1 < size && !visited.has(`${r},${c + 1}`)) {
                    cageCells.push({ row: r, col: c + 1 });
                    visited.add(`${r},${c + 1}`);
                } else if (Math.random() > 0.6 && r + 1 < size && !visited.has(`${r + 1},${c}`)) {
                    cageCells.push({ row: r + 1, col: c });
                    visited.add(`${r + 1},${c}`);
                }

                const values = cageCells.map(cell => solution[cell.row][cell.col]);
                let op = '';
                let target = 0;

                if (cageCells.length === 1) {
                    target = values[0];
                } else {
                    const coin = Math.random();
                    if (coin < 0.5) {
                        op = '+';
                        target = values.reduce((a, b) => a + b, 0);
                    } else {
                        op = '-';
                        target = Math.abs(values[0] - values[1]);
                    }
                }

                cages.push({ cells: cageCells, operation: op, target });
            }
        }

        return {
            title: "Kendoku Mantık Bulmacası",
            instruction: "Her satır ve sütunda rakamları tekrar etmeden, kafes içindeki işlemleri tamamla.",
            pedagogicalNote: "Çalışma belleği ve aritmetik muhakeme becerilerini güçlendirir.",
            puzzles: [{ size, grid, solution, cages }]
        };
    });
};
