const CompactCheckboxGroup = ({ label, options, selected, onChange }: any) => (
    <div className="space-y-2">
        <label className="text-[10px] font-black text-zinc-400 uppercase tracking-widest mb-1 block">{label}</label>
        <div className="grid grid-cols-2 gap-2">
