                <button
                    key={opt.value}
                    type="button"
                    onClick={() => {
                        const next = selected.includes(opt.value) 
                            ? selected.filter((v: string) => v !== opt.value)
                            : [...selected, opt.value];
                        onChange(next);
                    }}
                    className={`px-3 py-2 rounded-xl text-[10px] font-bold border-2 transition-all text-left flex items-center gap-2 ${selected.includes(opt.value) ? 'bg-indigo-600 border-indigo-600 text-white shadow-md' : 'bg-white dark:bg-zinc-800 border-zinc-200 dark:border-zinc-700 text-zinc-600 dark:text-zinc-400 hover:border-indigo-300'}`}
                >
                    <i className={`fa-solid ${selected.includes(opt.value) ? 'fa-square-check' : 'fa-square'} opacity-70`}></i>
                    {opt.label}
                </button>
            ))}
        </div>
    </div>
);

