export const KendokuSheet: React.FC<{ data: KendokuData }> = ({ data }) => {
    return (
        <div className="flex flex-col h-full bg-white text-black font-lexend">
            <PedagogicalHeader title={data.title} instruction={data.instruction} note={data.pedagogicalNote} />

            <div className="flex-1 flex flex-col items-center justify-center gap-10 mt-4">
                {(data.puzzles || []).map((puzzle, pIdx) => {
                    const size = puzzle.size;
                    const cellSize = size > 4 ? 60 : 80;

                    // Helper: get unique ID for a cage
                    const getCageId = (r: number, c: number) => {
                        return puzzle.cages.findIndex(cage => 
                            cage.cells.some(cell => cell.row === r && cell.col === c)
                        );
                    };

                    return (
                        <div key={pIdx} className="relative bg-white shadow-2xl border-[4px] border-zinc-900 rounded-lg overflow-hidden break-inside-avoid">
                            <div className="grid" style={{ 
                                gridTemplateColumns: `repeat(${size}, ${cellSize}px)`,
                                gridTemplateRows: `repeat(${size}, ${cellSize}px)`
                            }}>
                                {Array.from({ length: size * size }).map((_, idx) => {
                                    const r = Math.floor(idx / size);
                                    const c = idx % size;
                                    const cageId = getCageId(r, c);
                                    const cage = puzzle.cages[cageId];

                                    // Top-left cell of the cage gets the operator label
                                    const isFirstCell = cage.cells[0].row === r && cage.cells[0].col === c;

                                    // Border thickness logic: bold borders between different cages
                                    const borderTop = r === 0 || getCageId(r - 1, c) !== cageId;
                                    const borderBottom = r === size - 1 || getCageId(r + 1, c) !== cageId;
                                    const borderLeft = c === 0 || getCageId(r, c - 1) !== cageId;
                                    const borderRight = c === size - 1 || getCageId(r, c + 1) !== cageId;

                                    return (
                                        <div 
                                            key={idx} 
                                            className="relative flex items-center justify-center transition-colors hover:bg-zinc-50"
                                            style={{
                                                borderTop: borderTop ? '4px solid black' : '1px solid #e5e8eb',
                                                borderBottom: borderBottom ? '4px solid black' : '1px solid #e5e8eb',
                                                borderLeft: borderLeft ? '4px solid black' : '1px solid #e5e8eb',
                                                borderRight: borderRight ? '4px solid black' : '1px solid #e5e8eb'
                                            }}
                                        >
                                            {isFirstCell && (
                                                <div className="absolute top-0.5 left-1 text-[10px] font-black leading-none text-zinc-900 select-none z-10 uppercase">
                                                    {cage.target}{cage.operation}
                                                </div>
                                            )}

                                            <span className="text-2xl font-black text-indigo-600">
                                                <EditableText value={puzzle.grid[r][c] || ''} tag="span" />
                                            </span>
                                        </div>
                                    );
                                })}
                            </div>
                        </div>
                    );
                })}
            </div>

            <div className="mt-auto pt-6 flex justify-between items-center px-10 border-t border-zinc-100 opacity-40">
                <div className="flex gap-10">
                    <div className="flex flex-col">
                        <span className="text-[7px] font-black uppercase tracking-widest text-zinc-400">Kategori</span>
                        <span className="text-[10px] font-bold text-zinc-800 uppercase">Mantıksal Aritmetik</span>
                    </div>
                </div>
                <div className="text-right">
                    <p className="text-[7px] text-zinc-400 font-bold uppercase tracking-[0.4em]">Bursa Disleksi AI • Sayısal Zeka Laboratuvarı</p>
                </div>
            </div>
        </div>
    );
};

