                            label="Genişleme Katsayısı" 
                            value={options.expansionFactor || 1.5} 
                            onChange={(v:number) => handleChange('expansionFactor', v)} 
                            min={1} max={3} step={0.1} icon="fa-arrows-left-right" 
                        />
                        <CompactCounter 
                            label="Desen Sayısı" 
                            value={options.itemCount} 
                            onChange={(v:number) => handleChange('itemCount', v)} 
                            min={1} max={5} icon="fa-diamond" 
